"""pycparser.c_ast — C AST node types used by cffi's cparser."""


class Node:
    """Base AST node."""
    __slots__ = ('coord',)
    def __init__(self, coord=None):
        self.coord = coord
    def children(self):
        return ()
    def show(self, buf=None, offset=0, attrnames=False, nodenames=False, showcoord=False):
        pass


class NodeVisitor:
    def visit(self, node):
        method = 'visit_' + node.__class__.__name__
        return getattr(self, method, self.generic_visit)(node)
    def generic_visit(self, node):
        for child_name, child in node.children():
            self.visit(child)


class ArrayDecl(Node):
    __slots__ = ('type', 'dim', 'dim_quals')
    def __init__(self, type=None, dim=None, dim_quals=None, coord=None):
        self.type = type; self.dim = dim; self.dim_quals = dim_quals or []; self.coord = coord

class BinaryOp(Node):
    __slots__ = ('op', 'left', 'right')
    def __init__(self, op=None, left=None, right=None, coord=None):
        self.op = op; self.left = left; self.right = right; self.coord = coord

class Constant(Node):
    __slots__ = ('type', 'value')
    def __init__(self, type=None, value=None, coord=None):
        self.type = type; self.value = value; self.coord = coord

class Decl(Node):
    __slots__ = ('name', 'quals', 'align', 'storage', 'funcspec', 'type', 'init', 'bitsize')
    def __init__(self, name=None, quals=None, align=None, storage=None, funcspec=None,
                 type=None, init=None, bitsize=None, coord=None):
        self.name = name; self.quals = quals or []; self.align = align
        self.storage = storage or []; self.funcspec = funcspec or []
        self.type = type; self.init = init; self.bitsize = bitsize; self.coord = coord

